using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }

    if (n <= 3) {
        cout << 0 << endl;
        return 0;
    }

    vector<int> even_pos, odd_pos;
    for (int i = 0; i < n; ++i) {
        if (i % 2 == 0) {
            even_pos.push_back(arr[i]);
        } else {
            odd_pos.push_back(arr[i]);
        }
    }

    sort(even_pos.begin(), even_pos.end());
    sort(odd_pos.begin(), odd_pos.end());

    int second_largest_even = even_pos[even_pos.size() - 2];
    int second_smallest_odd = odd_pos[1];

    cout << second_largest_even + second_smallest_odd << endl;
    return 0;
}

