#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    if (n <= 3) {
        printf("0\n");
        return 0;
    }

    int even_count = 0, odd_count = 0;
    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) even_count++;
        else odd_count++;
    }

    int even_pos[even_count], odd_pos[odd_count];
    int e = 0, o = 0;

    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) even_pos[e++] = arr[i];
        else odd_pos[o++] = arr[i];
    }

    // Bubble sort for even_pos
    for (int i = 0; i < even_count - 1; i++) {
        for (int j = 0; j < even_count - i - 1; j++) {
            if (even_pos[j] > even_pos[j + 1]) {
                int temp = even_pos[j];
                even_pos[j] = even_pos[j + 1];
                even_pos[j + 1] = temp;
            }
        }
    }

    // Bubble sort for odd_pos
    for (int i = 0; i < odd_count - 1; i++) {
        for (int j = 0; j < odd_count - i - 1; j++) {
            if (odd_pos[j] > odd_pos[j + 1]) {
                int temp = odd_pos[j];
                odd_pos[j] = odd_pos[j + 1];
                odd_pos[j + 1] = temp;
            }
        }
    }

    int second_largest_even = even_pos[even_count - 2];
    int second_smallest_odd = odd_pos[1];

    printf("%d\n", second_largest_even + second_smallest_odd);

    return 0;
}

